import React, { useState } from 'react';
import { analyzeEmission, generateOptimization } from '../services/api';
import OptimizationScanner from '../components/OptimizationScanner';
import ComparisonTable from '../components/ComparisonTable';

function ResNetAnalysisPage({ onNavigateBack }) {
    const [step, setStep] = useState('IDLE'); // IDLE, RUNNING_BASELINE, ANALYZING, SHOW_SUGGESTIONS, OPTIMIZING, COMPLETED
    const [scanProgress, setScanProgress] = useState(0);
    const [baselineMetrics, setBaselineMetrics] = useState(null);
    const [analysisResult, setAnalysisResult] = useState(null);
    const [optimizationPlan, setOptimizationPlan] = useState(null);
    const [optimizedMetrics, setOptimizedMetrics] = useState(null);

    // Mock Data for Simulation
    const mockBaseline = {
        model: "ResNet-18",
        runtime_minutes: 30,
        co2_kg: 0.4500,
        power_usage_w: 250,
        energy_kwh: 0.1500,
        epochs: 10,
        batch_size: 64,
        gpu_load: 95
    };

    const runBaseline = () => {
        setStep('RUNNING_BASELINE');
        // Simulate Training
        setTimeout(() => {
            setBaselineMetrics(mockBaseline);
            setStep('BASELINE_DONE');
        }, 2000);
    };

    const startAnalysis = async () => {
        setStep('ANALYZING');
        setScanProgress(0);

        // Animate Scanner
        let progress = 0;
        const interval = setInterval(() => {
            progress += 5;
            setScanProgress(progress);
            if (progress >= 100) clearInterval(interval);
        }, 100);

        // Fetch Analysis Backend
        try {
            const analysis = await analyzeEmission(mockBaseline);
            const plan = await generateOptimization(mockBaseline);

            setTimeout(() => {
                setAnalysisResult(analysis.data);
                setOptimizationPlan(plan.data);
                setStep('SHOW_SUGGESTIONS');
            }, 2500);
        } catch (error) {
            console.error("Analysis Failed", error);
            setStep('BASELINE_DONE'); // Fallback
        }
    };

    const applyOptimization = () => {
        setStep('OPTIMIZING');
        setScanProgress(0);

        // Animate Scanner
        let progress = 0;
        const interval = setInterval(() => {
            progress += 2;
            setScanProgress(progress);
            if (progress >= 100) clearInterval(interval);
        }, 50);

        setTimeout(() => {
            setOptimizedMetrics({
                ...mockBaseline,
                runtime_minutes: 15,
                co2_kg: 0.2500,
                energy_kwh: 0.0850,
                epochs: optimizationPlan.optimized_config.epochs,
                batch_size: optimizationPlan.optimized_config.batch_size
            });
            setStep('COMPLETED');
        }, 5000); // Longer delay to simulate re-run
    };

    return (
        <div style={{ background: 'var(--bg-primary)', minHeight: '100vh', padding: '40px', position: 'relative' }}>
            {/* Headers */}
            <header style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '40px' }}>
                <button
                    onClick={onNavigateBack}
                    className="robotic-btn"
                    style={{
                        padding: '10px 20px',
                        background: 'rgba(0, 210, 255, 0.1)',
                        border: '1px solid var(--robotic-blue)',
                        color: '#fff',
                        cursor: 'pointer'
                    }}
                >
                    [ BACK_TO_HQ ]
                </button>
                <div style={{ color: 'var(--robotic-blue)', letterSpacing: '2px', fontWeight: 'bold' }}>
                    PROTOCOL: CO2_REDUCTION_WORKFLOW
                </div>
            </header>

            {/* Step 1: Baseline Run */}
            {step === 'IDLE' && (
                <div style={{ textAlign: 'center', marginTop: '100px' }}>
                    <h1 className="gradient-text" style={{ fontSize: '3rem', marginBottom: '40px' }}>INITIALIZE BASELINE MEASUREMENT</h1>
                    <button
                        onClick={runBaseline}
                        className="robotic-btn"
                        style={{
                            padding: '20px 60px',
                            fontSize: '1.5rem',
                            fontWeight: 'bold',
                            background: 'var(--primary-gradient)',
                            border: 'none',
                            color: '#000',
                            cursor: 'pointer',
                            boxShadow: '0 0 30px rgba(0,210,255,0.5)'
                        }}
                    >
                        START MODEL TRAINING
                    </button>
                </div>
            )}

            {step === 'RUNNING_BASELINE' && (
                <div style={{ textAlign: 'center', marginTop: '150px', color: 'var(--robotic-blue)' }}>
                    <h2>[ TRAINING_IN_PROGRESS ]</h2>
                    <p>Measuring Real-time Power Draw & Carbon Emissions...</p>
                    <div className="progress-bar" style={{ width: '50%', margin: '20px auto' }}>
                        <div className="progress-fill" style={{ animation: 'progressFill 2s infinite' }}></div>
                    </div>
                </div>
            )}

            {/* Baseline Result View */}
            {(step === 'BASELINE_DONE' || step === 'SHOW_SUGGESTIONS' || step === 'COMPLETED') && baselineMetrics && (
                <div className="glass-card fade-in" style={{ padding: '30px', marginBottom: '40px', borderLeft: '4px solid var(--accent-magenta)' }}>
                    <h3 style={{ color: '#fff', marginBottom: '20px' }}>📊 STEP 1: MEASURED BASELINE EMISSION</h3>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '20px', textAlign: 'center' }}>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>CO₂ Magnitude</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--accent-magenta)' }}>{baselineMetrics.co2_kg} kg</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Energy Used</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.energy_kwh} kWh</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Runtime</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.runtime_minutes} min</div>
                        </div>
                        <div>
                            <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Batch Size</div>
                            <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{baselineMetrics.batch_size}</div>
                        </div>
                    </div>

                    {step === 'BASELINE_DONE' && (
                        <div style={{ textAlign: 'center', marginTop: '40px' }}>
                            <button
                                onClick={startAnalysis}
                                className="robotic-btn"
                                style={{
                                    padding: '15px 40px',
                                    fontSize: '1.2rem',
                                    border: '2px solid var(--robotic-blue)',
                                    background: 'transparent',
                                    color: 'var(--robotic-blue)',
                                    cursor: 'pointer',
                                    boxShadow: '0 0 15px rgba(0,210,255,0.2)'
                                }}
                            >
                                [ ANALYZE & IDENTIFY ISSUES ]
                            </button>
                        </div>
                    )}
                </div>
            )}

            {/* Scanner Overlay */}
            {(step === 'ANALYZING' || step === 'OPTIMIZING') && (
                <OptimizationScanner
                    currentStep={step}
                    progress={scanProgress}
                />
            )}

            {/* Analysis & Suggestions View */}
            {(step === 'SHOW_SUGGESTIONS' || step === 'COMPLETED') && analysisResult && optimizationPlan && (
                <div className="fade-in">
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '40px', marginBottom: '40px' }}>
                        {/* Analysis Box */}
                        <div className="glass-card" style={{ padding: '30px', borderTop: '4px solid var(--warning-yellow)' }}>
                            <h3 style={{ color: 'var(--accent-orange)' }}>🧠 STEP 2: ALERT - HIGH EMISSION FACTORS</h3>
                            <ul style={{ listStyle: 'none', padding: 0, marginTop: '20px' }}>
                                {analysisResult.factors.map((factor, i) => (
                                    <li key={i} style={{ marginBottom: '15px', color: '#ffd700', display: 'flex', gap: '10px' }}>
                                        <span>⚠</span> {factor}
                                    </li>
                                ))}
                            </ul>
                        </div>

                        {/* Suggestions Box */}
                        <div className="glass-card" style={{ padding: '30px', borderTop: '4px solid var(--success-green)' }}>
                            <h3 style={{ color: 'var(--success-green)' }}>💡 STEP 3: OPTIMIZATION STRATEGY</h3>
                            <ul style={{ listStyle: 'none', padding: 0, marginTop: '20px' }}>
                                {optimizationPlan.suggestions.map((suggestion, i) => (
                                    <li key={i} style={{ marginBottom: '15px', color: '#fff', display: 'flex', gap: '10px' }}>
                                        <span style={{ color: 'var(--success-green)' }}>✓</span> {suggestion}
                                    </li>
                                ))}
                            </ul>
                        </div>
                    </div>

                    {step === 'SHOW_SUGGESTIONS' && (
                        <div style={{ textAlign: 'center' }}>
                            <button
                                onClick={applyOptimization}
                                className="robotic-btn"
                                style={{
                                    padding: '20px 50px',
                                    fontSize: '1.3rem',
                                    background: 'var(--primary-gradient)',
                                    border: 'none',
                                    color: '#000',
                                    fontWeight: 'bold',
                                    cursor: 'pointer',
                                    boxShadow: '0 0 30px rgba(0,242,254,0.4)',
                                    animation: 'pulse 2s infinite'
                                }}
                            >
                                APPLY OPTIMIZATIONS & RE-RUN MODEL
                            </button>
                            <p style={{ marginTop: '10px', color: 'var(--text-secondary)' }}>
                                Est. Reduction: {optimizationPlan.estimated_reduction_percentage}%
                            </p>
                        </div>
                    )}
                </div>
            )}

            {/* Final Comparison */}
            {step === 'COMPLETED' && optimizedMetrics && (
                <div className="fade-in">
                    {/* Simplified Result Card similar to image */}
                    <div className="glass-card" style={{ padding: '30px', marginBottom: '40px', background: 'rgba(0, 255, 127, 0.05)', border: '1px solid var(--success-green)' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <div>
                                <h2 style={{ color: '#fff', marginBottom: '10px' }}>Execution Result: ResNet-18 (Optimized)</h2>
                                <p style={{ color: 'var(--text-secondary)' }}>Calculation Finalized. Parameters Synchronized.</p>
                            </div>
                            <div style={{ textAlign: 'right' }}>
                                <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--success-green)' }}>
                                    🌿 SUSTAINABILITY SCORE: 92/100
                                </div>
                            </div>
                        </div>

                        <div style={{ display: 'flex', gap: '40px', marginTop: '30px' }}>
                            <div style={{ background: '#000', padding: '20px', borderRadius: '8px', minWidth: '200px' }}>
                                <div style={{ color: '#888', fontSize: '0.8rem' }}>Live CO₂ Accumulation</div>
                                <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--accent-cyan)' }}>{optimizedMetrics.co2_kg} <span style={{ fontSize: '1rem' }}>kg</span></div>
                            </div>
                            <div style={{ background: '#000', padding: '20px', borderRadius: '8px', minWidth: '200px' }}>
                                <div style={{ color: '#888', fontSize: '0.8rem' }}>Hardware Energy Pool</div>
                                <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#fff' }}>{optimizedMetrics.energy_kwh} <span style={{ fontSize: '1rem' }}>kWh</span></div>
                            </div>
                        </div>
                    </div>

                    <ComparisonTable baseline={baselineMetrics} optimized={optimizedMetrics} />

                    <div style={{ textAlign: 'center', marginTop: '60px' }}>
                        <button
                            onClick={runBaseline} // Reset
                            className="robotic-btn"
                            style={{
                                padding: '15px 30px',
                                background: 'transparent',
                                border: '1px solid var(--text-muted)',
                                color: 'var(--text-muted)',
                                cursor: 'pointer'
                            }}
                        >
                            [ START_NEW_SESSION ]
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

export default ResNetAnalysisPage;
